item.aggregated_output:
  1	{
  2	  "$schema": "https://json-schema.org/draft/2020-12/schema",
  3	  "title": "EDEN task",
  4	  "description": "A unit of work dispatched to a role. The task object carries kind, state, payload, and optional claim; its state-machine semantics are defined in 04-task-protocol.md.",
  5	  "type": "object",
  6	  "required": ["task_id", "kind", "state", "payload", "created_at", "updated_at"],
  7	  "properties": {
  8	    "task_id": {
  9	      "type": "string",
 10	      "minLength": 1
 11	    },
 12	    "kind": {
 13	      "type": "string",
 14	      "enum": ["plan", "implement", "evaluate"]
 15	    },
 16	    "state": {
 17	      "type": "string",
 18	      "enum": ["pending", "claimed", "submitted", "completed", "failed"]
 19	    },
 20	    "payload": {
 21	      "type": "object"
 22	    },
 23	    "claim": {
 24	      "type": "object",
 25	      "required": ["token", "worker_id", "claimed_at"],
 26	      "properties": {
 27	        "token": {
 28	          "type": "string",
 29	          "minLength": 1
 30	        },
 31	        "worker_id": {
 32	          "type": "string",
 33	          "minLength": 1
 34	        },
 35	        "claimed_at": {
 36	          "type": "string",
 37	          "format": "date-time",
 38	          "pattern": "^[0-9]{4}-[0-9]{2}-[0-9]{2}T[0-9]{2}:[0-9]{2}:[0-9]{2}(\\.[0-9]+)?Z$"
 39	        },
 40	        "expires_at": {
 41	          "type": "string",
 42	          "format": "date-time",
 43	          "pattern": "^[0-9]{4}-[0-9]{2}-[0-9]{2}T[0-9]{2}:[0-9]{2}:[0-9]{2}(\\.[0-9]+)?Z$"
 44	        }
 45	      }
 46	    },
 47	    "created_at": {
 48	      "type": "string",
 49	      "format": "date-time",
 50	      "pattern": "^[0-9]{4}-[0-9]{2}-[0-9]{2}T[0-9]{2}:[0-9]{2}:[0-9]{2}(\\.[0-9]+)?Z$"
 51	    },
 52	    "updated_at": {
 53	      "type": "string",
 54	      "format": "date-time",
 55	      "pattern": "^[0-9]{4}-[0-9]{2}-[0-9]{2}T[0-9]{2}:[0-9]{2}:[0-9]{2}(\\.[0-9]+)?Z$"
 56	    }
 57	  },
 58	  "allOf": [
 59	    {
 60	      "if": {"properties": {"kind": {"const": "plan"}}, "required": ["kind"]},
 61	      "then": {
 62	        "properties": {
 63	          "payload": {
 64	            "type": "object",
 65	            "required": ["experiment_id"],
 66	            "properties": {
 67	              "experiment_id": {"type": "string", "minLength": 1}
 68	            }
 69	          }
 70	        }
 71	      }
 72	    },
 73	    {
 74	      "if": {"properties": {"kind": {"const": "implement"}}, "required": ["kind"]},
 75	      "then": {
 76	        "properties": {
 77	          "payload": {
 78	            "type": "object",
 79	            "required": ["proposal_id"],
 80	            "properties": {
 81	              "proposal_id": {"type": "string", "minLength": 1}
 82	            }
 83	          }
 84	        }
 85	      }
 86	    },
 87	    {
 88	      "if": {"properties": {"kind": {"const": "evaluate"}}, "required": ["kind"]},
 89	      "then": {
 90	        "properties": {
 91	          "payload": {
 92	            "type": "object",
 93	            "required": ["trial_id"],
 94	            "properties": {
 95	              "trial_id": {"type": "string", "minLength": 1}
 96	            }
 97	          }
 98	        }
 99	      }
100	    },
101	    {
102	      "if": {"properties": {"state": {"const": "claimed"}}, "required": ["state"]},
103	      "then": {"required": ["claim"]},
104	      "else": {"not": {"required": ["claim"]}}
105	    }
106	  ]
107	}
